def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 1.5:
            priority += 1500 * usage_ratio
        elif usage_ratio > 1:
            priority += 1200
        elif usage_ratio == 1:
            priority += 250
        else:
            try:
                exp_val = np.exp(-usage_ratio * 10)
            except OverflowError:
                exp_val = 0.0
            priority += 40 * (1 - exp_val)
            if usage_ratio < 0.1:
                priority -= 10
            elif usage_ratio > 0.75 and usage_ratio < 1:
                priority += 50
            for j in range(2, 7):
                term = ((usage_ratio * j) % 1)
                if term < 0.3:
                    priority += (10 / j) * term
                else:
                    priority -= (5 / j) * (1 - term)
            if abs(usage_ratio - 0.5) < 0.1:
                priority += 20
        if capacity < 0.02:
            priority += 100
            if usage_ratio > 0.5:
                priority += 50
        elif capacity < 0.3:
            priority += 30
            if usage_ratio > 0.85:
                priority += 25
            for _ in range(2):
                priority += np.sin(capacity * 10) * 5
        else:
            if usage_ratio < 0.25:
                priority -= 15
            elif usage_ratio > 0.85:
                priority += 40
            for val in [0.33, 0.66]:
                dist = abs(usage_ratio - val)
                if dist < 0.07:
                    priority += 15 / (dist + 0.01)
        proximity_score = 0
        mod_capacity = int(capacity * 100)
        if mod_capacity % 4 == 0:
            proximity_score += 5
        if (mod_capacity + i) % 5 == 0:
            proximity_score -= 3
        for k in range(1, 5):
            marker = k / 5
            if abs(usage_ratio - marker) < 0.03:
                proximity_score += 12 / k
            else:
                proximity_score -= 1 / k
        if capacity * usage_ratio > 0.8:
            proximity_score += 10
        elif capacity * usage_ratio < 0.2:
            proximity_score -= 8
        priority += proximity_score
        if priority < 0:
            priority = 0
        priorities[i] = priority
    for idx in range(len(priorities)):
        if np.isfinite(priorities[idx]):
            neighborhood = priorities[max(0, idx - 2):min(len(priorities), idx + 3)]
            priorities[idx] += np.mean(neighborhood) * 0.1
    return priorities
